    ["ghostlyelixir_speed"] = "（Ghostly Elixir） 是 饥荒：联机版 中的一系列 可制作 物品。 在 温蒂 的 物品栏 中存有 阿比盖尔之花 时，温蒂可以右键使用灵体草药，为她的 阿比盖尔 提供增益。如果阿比盖尔死亡，增益效果就会立即结束。阿比盖尔拥有两个增益槽位，一个专门用于 光之怒 和 诅咒之苦，另一个用于所有其余灵体草药。",
    ["gift"] = "（Gift Wrap）是 饥荒：联机版 中的一种 可制作 物品。 礼物包装的工作原理与 捆绑包装 一致。 礼物（Gift） 是 饥荒：联机版 中的一种物品，可以使用礼物包装打包物品获得，除此之外，在 冬季盛宴 期间还有以下获取方式：",
    ["giftwrap"] = "（Gift Wrap）是 饥荒：联机版 中的一种 可制作 物品。 礼物包装的工作原理与 捆绑包装 一致。 礼物（Gift） 是 饥荒：联机版 中的一种物品，可以使用礼物包装打包物品获得，除此之外，在 冬季盛宴 期间还有以下获取方式：",
    ["glassblock"] = "玻璃城堡（Glass Castle） 是 饥荒：联机版 中的一种 物品。由 沙堡 点燃后变成。 玻璃尖刺（Glass Spike） 是 饥荒：联机版 中的一种 物品。由对应大小的 沙刺 点燃后变成。",
    ["glasscutter"] = "（Glass Cutter） 是 饥荒：联机版 中的一种 可制作 物品。 使用玻璃刀攻击大部分目标时，每次有效攻击都会消耗玻璃刀 1 次耐久，但是如果攻击目标是 暗影生物、 暗影棋子、 复活的骨架、 远古织影者 及其召唤的 编织暗影 和 看不见的手、 熔合暗影 或 墨荒，每次有效攻击消耗 0.5 次耐久。",
    ["glassspike"] = "玻璃城堡（Glass Castle） 是 饥荒：联机版 中的一种 物品。由 沙堡 点燃后变成。 玻璃尖刺（Glass Spike） 是 饥荒：联机版 中的一种 物品。由对应大小的 沙刺 点燃后变成。",
    ["glassspike_med"] = "玻璃城堡（Glass Castle） 是 饥荒：联机版 中的一种 物品。由 沙堡 点燃后变成。 玻璃尖刺（Glass Spike） 是 饥荒：联机版 中的一种 物品。由对应大小的 沙刺 点燃后变成。",
    ["glassspike_short"] = "玻璃城堡（Glass Castle） 是 饥荒：联机版 中的一种 物品。由 沙堡 点燃后变成。 玻璃尖刺（Glass Spike） 是 饥荒：联机版 中的一种 物品。由对应大小的 沙刺 点燃后变成。",
    ["glassspike_tall"] = "玻璃城堡（Glass Castle） 是 饥荒：联机版 中的一种 物品。由 沙堡 点燃后变成。 玻璃尖刺（Glass Spike） 是 饥荒：联机版 中的一种 物品。由对应大小的 沙刺 点燃后变成。",
    ["glommerflower"] = "（Glommer's Flower） 是 饥荒：联机版 中的一种 物品，在 满月 时生成于 格罗姆雕像。 当世界内存在一个格罗姆花时， 格罗姆 也会一同生成，并跟随格罗姆花。 当 格罗姆 死亡时，格罗姆花就会枯萎，此时可以用作燃料，燃烧值为 90 秒。",
    ["glommerfuel"] = "（Glommer's Goop） 是 饥荒：联机版 中的 物品。 格罗姆的黏液是 肥料，能够提供 8 催长剂、8 堆肥 和 8 粪肥 的营养物质。",
    ["glommerwings"] = "（Glommer's Wings） 是 饥荒：联机版 中的一种 物品。",
    ["glowberrymousse"] = "（Glow Berry Mousse） 是 饥荒：联机版 中的一种 物品。 食用发光浆果慕斯的角色自身会成为光源提供照明，效果持续 2 天。随着游戏时间进行，照明范围会逐渐缩小。",
    ["glowfly"] = "（Glowfly） 是 饥荒 中的一种 生物，会从玩家 25 距离单位 1 距离单位等于 1/4 地块 边长，即一般情况下放置墙壁的最小间隔，也是建筑对齐网格的默认间隔。 内的 异域花朵 处生成，在 平和季 末尾生成的数量会大大增加。 进入 潮湿季 前的某一刻，所有屏幕内的发光飞虫都将落地变为 发光飞虫茧。 击杀发光飞虫会为玩家增加 1 点 淘气值。",
    ["gnarwail_horn"] = "（Gnarwail Horn） 是 饥荒：联机版 中的一种 物品，由 一角鲸 和 一角鲸钻洞攻击 死亡后掉落 1 个；敲开 沉底宝箱 中有 10% 概率开出。 一角鲸的角是一件手部装备，拥有 10 次使用耐久，作为武器使用不消耗耐久，每次演奏消耗 1 次使用耐久。",
    ["goatmilk"] = "（Electric Milk） 是 饥荒：联机版 中的一种 物品。 带电的羊奶可作为食材放入锅中 烹饪，提供 1 乳制品度。",
    ["gogglesarmorhat"] = "（Visor） 是 饥荒 中的一种 可制作 物品。只能由 瓦格斯塔夫 制作。 装备面甲可以消除 瓦格斯塔夫 的近视效果，但会在屏幕上添加一个遮挡视野，使玩家只能看到一个小方形区域内的东西。如果使用瓦格斯塔夫以外的角色装备它，它会反而为玩家添加近视效果。 当玩家装备护目眼镜时，角色会有概率说出以下台词：",
    ["goggleshat"] = "（Fashion Goggles） 是 饥荒：联机版 中的一种 可制作 物品。 时髦的护目镜的皮肤也可以应用于 沙漠护目镜。 织造-优雅 侦探护目镜 作为一名侦探最棒的事情就是拥有侦探的外观！",
    ["gogglesheathat"] = "（Infroggles） 是 饥荒 中的一种 可制作 物品。只能由 瓦格斯塔夫 制作。 装备红外线护目镜可以消除 瓦格斯塔夫 的近视效果。如果使用瓦格斯塔夫以外的角色装备它，它会反而为玩家添加近视效果。 当瓦格斯塔夫装备它时，它能够提供夜视效果，在黑暗中也能看清东西，不会受到 黑暗 的伤害，但是并不能给其他玩家或生物等提供光照效果。",
    ["gogglesnormalhat"] = "（Spectoggles） 是 饥荒 中的一种 可制作 物品，只能由 瓦格斯塔夫 制作。瓦格斯塔夫出生时自带 1 个护目眼镜。 当玩家装备护目眼镜时，角色会有概率说出以下台词： 哈！当你能看清这个世界时，才能感受它更多有趣的地方。",
    ["gogglesshoothat"] = "（Fryfocals） 是 饥荒 中的一种 可制作 物品。只能由 瓦格斯塔夫 制作。 装备镭射焦点可以消除 瓦格斯塔夫 的近视效果并为视野添加黄色滤镜。如果使用 瓦格斯塔夫 以外的 角色 装备它，它会反而为玩家添加近视效果。 当玩家卸下手部装备时可以使用镭射焦点攻击，并点燃目标。可以为熄灭的 营地火源 添加 15 燃料值的 燃料。",
    ["gold_dust"] = "（Gold Dust） 是 饥荒 中的一种 物品。对 闪光的水坑 使用一次 淘金盘 可以产生一个砂金。 淘金兽、 鼹鼠、 石虾、 蛞蝓龟 和 蜗牛龟 会吃砂金。 该 制作配方 需要在玩家位于 猪镇世界 时，才能制作原型并 解锁。",
    ["golden_farm_hoe"] = "（Garden Hoe） 和 黄金园艺锄（Splendid Garden Hoe） 是 饥荒：联机版 中的 可制作 物品。 园艺锄是用来给 农田地块 犁地的工具。装备上之后在农田地块上方右键，即可在选定位置犁出一个能用于种植 种子 的土堆。犁地时各个土堆应该保持一定距离，犁的太近会摧毁周围不符合当前犁地距离的土堆。",
    ["goldenaxe"] = "（Axe） 和 黄金斧头（Luxury Axe） 是 饥荒：联机版 中的 可制作 物品。部分 失败的求生者 和 布景 中也会出现斧头。 斧头和黄金斧头可以用于砍伐 可砍伐 的实体，使用它进行砍伐工作时具有 1 工作效率 每次对 可作业 实体工作时，其剩余工作次数会相应减少一定数值，这个数值由工具的工作效率和角色自身倍率或 蜂蜜水晶 的效果相乘得到。",
    ["goldenmachete"] = "（Machete） 和 黄金砍刀（Machete） 是 饥荒 中的一种 可制作 物品。砍刀自然生成于 坠毁的热气球布景、 草状装置布景。 砍刀可用于劈砍 竹林、 藤蔓 等 可劈砍 的物体。 黄金砍刀的用途与砍刀相同，但是耐久是砍刀的 4 倍。",
    ["goldenpickaxe"] = "（Pickaxe） 和 黄金鹤嘴锄（Opulent Pickaxe） 是 饥荒：联机版 中的 可制作 物品。 鹤嘴锄和黄金鹤嘴锄可以用来开采 可开采 的实体，使用它进行开采工作时具有 1 工作效率 每次对 可作业 实体工作时，其剩余工作次数会相应减少一定数值，这个数值由工具的工作效率和角色自身倍率或 蜂蜜水晶 的效果相乘得到。",
    ["goldenpitchfork"] = "（Pitchfork） 和 黄金干草叉（Snazzy Pitchfork） 是 饥荒：联机版 中的 可制作 物品。 干草叉和黄金干草叉可以用来挖掘 地块，装备之后会在指针处显示地块方格。右键点击即可挖掘，默认情况下生成对应的 地皮。 干草叉和黄金干草叉在被当作武器使用时，每次攻击会损耗 8 次耐久。",
    ["goldenshovel"] = "（Shovel） 和 黄金铲子（Regal Shovel） 是 饥荒：联机版 中的 可制作 物品。 铲子和黄金铲子可以用于挖掘 草、 树苗、 浆果丛 等 可挖掘 实体。 织造-杰出 猎人铲子 为自力更生的冒险家准备的一把铲子。",
    ["goldnugget"] = "（Gold Nugget） 是 饥荒：联机版 中的一种 可制作 物品。自然生成于 混合地群系、 石虾地群系、 蜘蛛矿区群系、 大蝙蝠洞群系、 蝙蝠居处群系。 像大多数矿物一样，金块放在地上时会被 地震 的掉落物砸碎。",
    ["goldpan"] = "（Gold Pan） 是 饥荒 中的一种 可制作 物品。 淘金盘可对 闪光的水坑 使用，使其水位降低一个阶段，产生一个 砂金。 淘金盘可以放入 炼钢炉 中冶炼为 合金。",
    ["goose_feather"] = "（Down Feather） 是 饥荒：联机版 中的一种 物品。",
    ["grass"] = "（Grass） 是 饥荒：联机版 中的一种 植物。当 开始资源 为草时，自然生成于 多个生物群系 蜜蜂池塘区群系、 洞穴入口六群系、 杀人蜂平原群系、 繁花陨石区群系、 出生地群系、 洞穴入口十群系、 恶地群系、 洞穴入口四群系、 地下森林群系、 兔人镇群系、 海象平原群系、 绿蘑菇森林群系、 洞穴入口二群系、 洞穴入口八群系、 猪村森林群系、 兔人城群系…",
    ["grass_umbrella"] = "（Pretty Parasol） 是 饥荒：联机版 中的一种 可制作 物品。 织造-优雅 玫瑰阳伞 姐妹的旧衣服系列 \"四月雨催开五月花。\"",
    ["graveurn"] = "（Spirit Vessel） 是 饥荒：联机版 中的一种 可制作 物品。 灵魂容器的主要用途是用来迁移 墓碑： 学习了“坟墓美化”技能的温蒂可以用灵魂容器对 墓碑 进行“请君入瓮”，将其收入灵魂容器内。",
    ["gravy"] = "（Winter's Feast Dishes） 是 饥荒：联机版 中的一类 可制作 物品，需要通过在 砖砌烤炉 旁制作来获得。 冬季盛宴菜肴可被放置在 冬季盛宴餐桌 上享用，以获得“冬季欢愉”增益，详见 冬季盛宴餐桌。 原文单词中“merry”通常用来指代圣诞期间的“快乐”，“berry sauce”则是果酱，莓果酱的意思；",
    ["green_cap"] = "（Mushrooms） 是 饥荒：联机版 中的一类实体，包括 红蘑菇（Red Mushroom）、 绿蘑菇（Green Mushroom）、 蓝蘑菇（Blue Mushroom）。 蘑菇在对应时间段会从地里长出来，可以采集，其它时间则会缩回去。红蘑菇对应 白天，绿蘑菇对应 黄昏，蓝蘑菇对应 夜晚。",
    ["green_cap_cooked"] = "（Mushrooms） 是 饥荒：联机版 中的一类实体，包括 红蘑菇（Red Mushroom）、 绿蘑菇（Green Mushroom）、 蓝蘑菇（Blue Mushroom）。 蘑菇在对应时间段会从地里长出来，可以采集，其它时间则会缩回去。红蘑菇对应 白天，绿蘑菇对应 黄昏，蓝蘑菇对应 夜晚。",
    ["green_mushroom"] = "（Mushrooms） 是 饥荒：联机版 中的一类实体，包括 红蘑菇（Red Mushroom）、 绿蘑菇（Green Mushroom）、 蓝蘑菇（Blue Mushroom）。 蘑菇在对应时间段会从地里长出来，可以采集，其它时间则会缩回去。红蘑菇对应 白天，绿蘑菇对应 黄昏，蓝蘑菇对应 夜晚。",
    ["green_mushroomhat"] = "（Funcap） 是 饥荒：联机版 中的一系列 可制作 物品，有三种不同颜色的蘑菇帽。它们的制作配方只能由学习 毒菌蟾蜍 掉落的对应 稀有蓝图 来解锁。 毒菌蟾蜍会随机掉落 1 种颜色的蘑菇帽稀有蓝图， 悲惨的毒菌蟾蜍 则会随机掉落 2 种颜色的蘑菇帽稀有蓝图。 蘑菇帽 完全腐烂 后会直接消失，不会生成 腐烂物。",
    ["greenamulet"] = "（Construction Amulet） 是 饥荒：联机版 中的一种 可制作 物品。 装备时，每次 制作 消耗的材料减半（向上取整），并消耗 1 次耐久。 织造-优雅 强健护符 圣物系列 成本减半，但质量依然坚挺。",
    ["greengem"] = "（Green Gem） 是 饥荒：联机版 中的一种 可制作 物品。 绿宝石可以被镶嵌入沉睡的 帝王蟹，也可用于给 薇诺娜的宝石发电机 提供能量。",
    ["greenmooneye"] = "（Moonlens） 是 饥荒：联机版 的一类 物品，通过将不同颜色的 宝石 包括 红宝石、 蓝宝石、 紫宝石、 橙宝石、 黄宝石 和 绿宝石 （下同）插入 带孔月岩 来获得。 当它掉落在地面上时，月眼会出现在地图上，并共享给游戏内的所有玩家，即使在未探索的区域也是如此。 紫色月眼是将 绚丽之门 升级为 天体传送门 的必备材料。",
    ["greenstaff"] = "（Deconstruction Staff） 是 饥荒：联机版 中的一种 可制作 物品。 拆解魔杖装备时，可以与建筑或物品互动，将其拆解为它的制作材料，消耗 20。 用拆解魔杖攻击不消耗耐久。",
    ["guacamole"] = "（Guacamole） 是 饥荒：联机版 中的一种 物品。 鳄梨酱只能由 烹饪 产生。烹饪配方为：至少 1 个 鼹鼠，至少 1 个 仙人掌肉 / 成熟石果，不包含 水果度。优先级为 10，需要花费 10 秒。",
    ["guano"] = "（Guano） 是 饥荒：联机版 中的一种 物品。 鸟粪是 肥料，能够提供 16 粪肥 的营养物质。",
    ["gummy_cake"] = "（Gummy Cake） 是 饥荒 中的一种 物品。 软糖蛋糕的外观会在 猪人庆典 期间有所不同。 软糖蛋糕只能由 烹饪 产生。烹饪配方为： 甜味剂度 大于 0，至少 1 个 糖蛞蝓 / 熟糖蛞蝓。优先级为 1，需要花费 40 秒。",
    ["gunpowder"] = "（Gunpowder） 是 饥荒：联机版 中的一种 可制作 物品。 火药在被 点燃 后会在燃尽时 爆炸，在 3 距离单位 1 距离单位等于 1/4 地块 边长，即一般情况下放置墙壁的最小间隔，也是建筑对齐网格的默认间隔。 内： 爆炸还会对所在 码头地块 造成 200 点伤害。",
    ["hail_ice"] = "（Hail） 是 饥荒 中的一种 物品。 冰雹只会在 风暴 期间，生成在角色半径 20 距离单位 1 距离单位等于 1/4 地块 边长，即一般情况下放置墙壁的最小间隔，也是建筑对齐网格的默认间隔。 内，最大生成频率为每分钟 45 个。 【待验证】 冰雹在 冰箱、 冰雪切斯特 中或 环境温度 低于 0 时， 腐烂速度 变为 0。",
    ["halberd"] = "（Halberd） 是 饥荒 中的一种 可制作 物品。 戟是一件 手部装备，可以用于战斗和砍伐 树木。 戟可以放入 炼钢炉 中冶炼为 合金。",
    ["halloween_experiment_bravery"] = "是 饥荒：联机版 中的一类 可制作 物品，只能在 疯狂科学家实验室 附近制作。 恐惧实验（Phobic Experiment），有 67% 概率产出 减轻恐惧的药液（Brew of Phobic Abatement），33% 概率产出 终止恐惧的药液（Brew of Phobic Abrogation）。",
