    ["honeynuggets"] = "（Honey Nuggets） 是 饥荒：联机版 中的一种 物品。 蜜汁卤肉是 伍迪 的 最喜欢的食物。 蜜汁卤肉只能由 烹饪 产生，制作配方为：至少 1 个 蜂蜜， 肉度 大于 0 小于等于 1.5，没有 不可食用度。优先级为 2，需要花费 40 秒。",
    ["horn"] = "（Beefalo Horn） 是 饥荒：联机版 中的一种 物品。 演奏牛角可以使 25 距离单位 1 距离单位等于 1/4 地块 边长，即一般情况下放置墙壁的最小间隔，也是建筑对齐网格的默认间隔。 半径内的最多 5 头 皮弗娄牛 聚集跟随玩家；如果它们绑定了 皮弗娄牛铃，还会解除与铃铛的绑定。",
    ["horrorfuel"] = "（Pure Horror） 是 饥荒：联机版 中的一种 可制作 物品。 纯粹恐惧可以为 噩梦燃料消耗者 添加燃料或修理，燃料值为 噩梦燃料 的 2 倍。 与 噩梦燃料 一样，纯粹恐惧不会 潮湿。",
    ["horseshoe"] = "（Lucky Horseshoe） 是 饥荒：联机版 中的一种 物品。 幸运马蹄铁作为 幸运物品，每个增加 0.05 的 幸运值。如果玩家装备了 镀金骑士套装，那么每个幸运马蹄铁，增加 0.1 的幸运值。",
    ["hotchili"] = "（Spicy Chili） 是 饥荒：联机版 中的一种 物品。 辣椒炖肉是 薇洛 的 最喜欢的食物。 辣椒炖肉只能由 烹饪 产生。烹饪配方为： 肉度 大于等于 1.5， 蔬菜度 大于等于 1.5，优先级为 10，需要花费 10 秒。",
    ["houndstooth"] = "（Hound's Tooth） 是 饥荒：联机版 中的一种 可制作 物品。",
    ["houndstooth_blowpipe"] = "（Howlitzer） 是 饥荒：联机版 中的一种 可制作 物品。 嚎弹炮具有 1 个物品栏，可以装填 犬牙 作为弹药，每次攻击消耗 1 个犬牙。它的射弹是直线飞行，不具有追踪效果，不能对目标以外的生物造成伤害，锁定的目标消失后射弹也将消失。 嚎弹炮对 暗影阵营 目标造成 1.1 倍 该倍率属于 进攻端标签伤害倍率，对 物理伤害 和 位面伤害 均有效。",
    ["houndwhistle"] = "（Lucky Whistle） 是 饥荒：联机版 中的一种 可制作 物品。 玩家每次吹响幸运哨子时，附近 25 距离单位 1 距离单位等于 1/4 地块 边长，即一般情况下放置墙壁的最小间隔，也是建筑对齐网格的默认间隔。",
    ["humanmeat"] = "（Long Pig） 是 饥荒：联机版 中的一种 物品。 在 火源 上 烹饪 长猪，就会变成 熟长猪（Cooked Long Pig）。 在 晾肉架 上晾干长猪，就会变成 长猪肉干（Long Pig Jerky）。",
    ["humanmeat_cooked"] = "（Long Pig） 是 饥荒：联机版 中的一种 物品。 在 火源 上 烹饪 长猪，就会变成 熟长猪（Cooked Long Pig）。 在 晾肉架 上晾干长猪，就会变成 长猪肉干（Long Pig Jerky）。",
    ["humanmeat_dried"] = "（Long Pig） 是 饥荒：联机版 中的一种 物品。 在 火源 上 烹饪 长猪，就会变成 熟长猪（Cooked Long Pig）。 在 晾肉架 上晾干长猪，就会变成 长猪肉干（Long Pig Jerky）。",
    ["hutch_fishbowl"] = "（Star-Sky） 是 饥荒：联机版 中的一种 物品，自然生成 1 个于 洞穴世界 的 泥坑区群系。 在玩家第一次拿起后， 哈奇 会出现并持续跟随星空。如果哈奇死亡，星空会在一天后在生成一只新的哈奇。 沃特 的物品栏中有星空时，每分钟会回复 3.3。",
    ["ice"] = "（Ice） 是 饥荒：联机版 中的一种 物品。 冰可以用于扑灭焖烧或正在 燃烧 的实体，可以为 冰帽 回复 25%（2 天） 新鲜度，也可以为 浇水壶、 鸟嘴壶 回复 1 次耐久。 冰在 冰箱、 冰雪切斯特 中或 环境温度 低于 0 时， 腐烂速度 变为 0。在燃源附近时，或在 燃烧 状态 角色 的 物品栏 内时，腐烂速度会 ×3000%。",
    ["ice_blueprint"] = "（Costume Patterns） 是 饥荒：联机版 中的一类物品。 礼服款式由 礼服款式碎片 通过 缝纫机 缝制而得到。",
    ["icecream"] = "（Ice Cream） 是 饥荒：联机版 中的一种 物品。 冰淇淋是 韦伯 的 最喜欢的食物。 冰淇淋只能由 烹饪 产生。烹饪配方为： 甜味剂度、 冰度 和 乳制品度 大于 0，且没有 肉度、 蔬菜度、 不可食用度 和 蛋度，优先级为 10，需要花费 10 秒。",
    ["icedtea"] = "（Iced Tea） 是 饥荒 中的一种 物品。 冰茶的外观会在 猪人庆典 期间有所不同。 喝下冰茶会提高 1.67 点移动速度，持续 80 秒；该效果与 同种效果 不叠加，后获得的效果会覆盖先前的效果，无论时长和加速效果。",
    ["icehat"] = "（Ice Cube） 是 饥荒：联机版 中的一种 可制作 物品。 冰帽装备时会提供 40 度的 冷源。 若装备者为 角色 且 潮湿度 低于 50，则提供每秒 1 的 装备潮湿速率；若潮湿度高于 50，则提供每秒 $\\min(1, \\text{干燥速率})$ 的装备潮湿速率。",
    ["icepack"] = "（Insulated Pack） 是 饥荒：联机版 中的一种 可制作 物品。 保鲜背包提供 8 个 物品栏，并且能使放置在里面的物品减缓 50% 的 腐烂 速度，装备时，保鲜背包的物品栏会显示在屏幕右侧，成为玩家物品栏的一部分，帮助玩家携带和管理更多的物品。",
    ["icestaff"] = "（Ice Staff） 是 饥荒：联机版 中的一种 可制作 物品。也自然生成于 冰魔杖陷阱 和个别 失败的求生者 中。 冰魔杖是一件远程武器。它的攻击本身没有任何伤害，但可以给目标施加 1 层 冰冻 效果，并使其进入受击的硬直。 冰魔杖可以用于扑灭 火焰 和 闷烧。",
    ["icestaff2"] = "（Ice Staff） 是 饥荒：联机版 中的一种 可制作 物品。也自然生成于 冰魔杖陷阱 和个别 失败的求生者 中。 冰魔杖是一件远程武器。它的攻击本身没有任何伤害，但可以给目标施加 1 层 冰冻 效果，并使其进入受击的硬直。 冰魔杖可以用于扑灭 火焰 和 闷烧。",
    ["icestaff3"] = "（Ice Staff） 是 饥荒：联机版 中的一种 可制作 物品。也自然生成于 冰魔杖陷阱 和个别 失败的求生者 中。 冰魔杖是一件远程武器。它的攻击本身没有任何伤害，但可以给目标施加 1 层 冰冻 效果，并使其进入受击的硬直。 冰魔杖可以用于扑灭 火焰 和 闷烧。",
    ["infused_iron"] = "（Infused Iron） 是 饥荒 中的一种 物品。由 远古兵器 死亡掉落。主要的用途只有制作 活性机甲。 注能铁块保质期结束后会变为 铁矿石。",
    ["inspectacleshat"] = "（Inspectacles） 是 饥荒：联机版 中的一种 可制作 物品。 每隔 0.5 天，装备检查专用镜后，会在 薇诺娜 附近 26 到 54 距离单位 1 距离单位等于 1/4 地块 边长，即一般情况下放置墙壁的最小间隔，也是建筑对齐网格的默认间隔。 处刷出 藏物箱。 如果藏物箱在屏幕范围外，那么就会在屏幕边缘出现一道蓝色光波提示藏物箱所在的方向。",
    ["ipecacsyrup"] = "（Syrup of Ipecaca） 是 饥荒：联机版 中的一种 可制作 物品。 当喂给能产生 粪肥 的生物时，将会赋予该生物“泻根中毒”的负面效果，持续 45 秒。 泻根中毒会使得该生物每 3 秒会减少 5 生命值、产生 1 个 粪肥，并使其持续恐慌。",
    ["iron"] = "（Iron Ore） 是 饥荒 中的一种 物品。自然生成于 荒野雨林群系、 未知边缘二群系、 彩绘沙地群系。由采集 雷鸟巢，或 注能铁块 腐烂 后获得。 铁矿石可以放入 炼钢炉 中冶炼为 合金。",
    ["ironwind"] = "（Iron Wind） 是 饥荒 中的一类 可制作 物品。 可以被装备到 船尾栏，装备后提高 50% 的移动速度，加速度提升到 18速度单位/秒。同时在移动时解放角色的双手，让他们能够同时使用 火把、 提灯 和 水瓶提灯 等手部装备 【待验证】 可以使用 齿轮 修复，每个齿轮修复25%的耐久。",
    ["ivy_snare"] = "（Weeds） 是 饥荒：联机版 中的一类作物。它们会干涉普通 农作物 的生长，给予 杂物压力，但它们本身的产物也会带来一定的好处。 饥荒：联机版 中共有四种杂草，分别是 必忘我（Forget-Me-Lots）、 犁地草（Tillweed）、 火荨麻（Fire Nettles）、 刺针旋花（Spiny Bindweed）。",
    ["jammypreserves"] = "（Fist Full of Jam） 是 饥荒：联机版 中的一种 物品。 果酱只能由 烹饪 产生。烹饪配方为： 水果度 大于 0，没有 肉度、 蔬菜度 和 不可食用度。优先级为 0，需要花费 10 秒。 由于其恢复的属性值较低，果酱通常被认为是一道“惩罚料理”，一般只会在处理临期的浆果或烤浆果时会特意制作。",
    ["jellybean"] = "（Jellybeans） 是 饥荒：联机版 中的一种 物品。 吃彩虹糖豆可以在 2 分钟内每 2 秒恢复 2，加上即时效果一共恢复 122。 彩虹糖豆只能由 烹饪 产生，烹饪配方为：至少含有 1 个 蜂王浆，没有 不可食用度 和 怪物度，优先级为 12，需要花费 50 秒，每次烹饪产出 3 个。",
    ["jellybug"] = "（Bean Bugs） 是 饥荒 中的一种 物品。翻开 小石板 有概率掉落。 在 火源 上 烹饪 豆虫，就会变成 熟豆虫（Cooked Bean Bugs）。 豆虫、熟豆虫可作为食材放入锅中 烹饪，提供 1 昆虫度。",
    ["jellybug_cooked"] = "（Bean Bugs） 是 饥荒 中的一种 物品。翻开 小石板 有概率掉落。 在 火源 上 烹饪 豆虫，就会变成 熟豆虫（Cooked Bean Bugs）。 豆虫、熟豆虫可作为食材放入锅中 烹饪，提供 1 昆虫度。",
    ["jellyfish"] = "（Jellyfish） 是 饥荒 中的一种 生物。自然生成于 珊瑚礁区块。也可以由水母生成点生成。 如果有生物使用近战攻击攻击水母，会受到 5 点伤害并和触电的长硬直。 可以使用 拖网 或 网 捕捉水母。",
    ["jellyfish_cooked"] = "（Dead Jellyfish） 是 饥荒 中的一种 物品。 在 火源 上烹饪 水母 或死水母，就会变成 熟水母（Cooked Jellyfish）。 在 晾肉架 上晾干死水母、 死彩虹水母，就会变成 晾干的水母（Dried Jellyfish）。",
    ["jellyfish_dead"] = "（Dead Jellyfish） 是 饥荒 中的一种 物品。 在 火源 上烹饪 水母 或死水母，就会变成 熟水母（Cooked Jellyfish）。 在 晾肉架 上晾干死水母、 死彩虹水母，就会变成 晾干的水母（Dried Jellyfish）。",
    ["jellyfish_planted"] = "（Jellyfish） 是 饥荒 中的一种 生物。自然生成于 珊瑚礁区块。也可以由水母生成点生成。 如果有生物使用近战攻击攻击水母，会受到 5 点伤害并和触电的长硬直。 可以使用 拖网 或 网 捕捉水母。",
    ["jellyjerky"] = "（Dead Jellyfish） 是 饥荒 中的一种 物品。 在 火源 上烹饪 水母 或死水母，就会变成 熟水母（Cooked Jellyfish）。 在 晾肉架 上晾干死水母、 死彩虹水母，就会变成 晾干的水母（Dried Jellyfish）。",
    ["jellyopop"] = "（Jelly-O Pop） 是 饥荒 中的一种 物品。 水母冻可用于与 海盗章鱼 交易，换取 海上陷阱。 水母冻只能由 烹饪 产生。烹饪配方为： 水母度、 冰度、 不可食用度 大于 0。优先级为 20，需要花费 10 秒。",
    ["jungle"] = "（Jungle Turf） 是 饥荒 中的一种 地皮。可以通过挖 丛林地块 获得。 可以铺设于 空白地块，将其变为丛林地块。",
    ["jungletreeseed"] = "（Jungle Tree Seed） 是 饥荒 中的一种 物品，由砍伐 丛林树 掉落。 丛林树种子可以种植于地面，成为 丛林树苗（Jungle Tree Sapling）。 丛林树苗会在 3.75 ~ 5.25 天后成长为一棵矮小阶段的丛林树。",
    ["justeggs"] = "（Plain Omelette） 是 饥荒：联机版 中的一种 物品。 普通煎蛋只能 烹饪 产生。烹饪配方为： 蛋度 大于等于 3。优先级为 0，需要花费 10 秒。",
    ["kabobs"] = "（Kabobs） 是 饥荒：联机版 中的一种 物品。 肉串只能由 烹饪 产生。制作配方为：至少有 1 个 树枝， 肉度 大于 0， 怪物度 和 不可食用度 小于等于 1。优先级为 5，需要花费 40 秒。",
    ["kelp"] = "（Kelp Fronds） 是 饥荒：联机版 中的一种 物品。通过采集 公牛海带、采集 海洋残骸 或与 鱼人之王 交易获得。 在 火源 上 烹饪 海带叶，就会变成 熟海带叶（Cooked Kelp Fronds）。 在 晾肉架 上晾干海带叶，就会变成 干海带叶（Dried Kelp Fronds）。",
    ["kelp_cooked"] = "（Kelp Fronds） 是 饥荒：联机版 中的一种 物品。通过采集 公牛海带、采集 海洋残骸 或与 鱼人之王 交易获得。 在 火源 上 烹饪 海带叶，就会变成 熟海带叶（Cooked Kelp Fronds）。 在 晾肉架 上晾干海带叶，就会变成 干海带叶（Dried Kelp Fronds）。",
    ["kelp_dried"] = "（Kelp Fronds） 是 饥荒：联机版 中的一种 物品。通过采集 公牛海带、采集 海洋残骸 或与 鱼人之王 交易获得。 在 火源 上 烹饪 海带叶，就会变成 熟海带叶（Cooked Kelp Fronds）。 在 晾肉架 上晾干海带叶，就会变成 干海带叶（Dried Kelp Fronds）。",
    ["kelphat"] = "（Seawreath） 是 饥荒：联机版 中的一种 可制作 物品。 海花环 完全腐烂 时会直接消失。 沃特 佩戴海花环时反而会 + 1.33 /分钟。",
    ["key_to_city"] = "（Key to the City） 是 饥荒 中的一种 物品。可以通过消耗 皇家画廊钥匙 在 宫殿 打开 皇家画廊展柜 得到。 城镇之钥是一个 制作站，靠近或放在 物品栏 中时可以制作 城镇规划栏 中的物品。它制作的所有物品都不会永久解锁，想要再次制作某一物品配方时，必须回到制作站处。 城镇之钥可以制作以下配方：",
    ["killerbee"] = "（Bee） 和 杀人蜂（Killer Bee） 是 饥荒：联机版 中的两种 生物。 在 春季，蜜蜂会有跟 杀人蜂 一样的外观。 蜜蜂和杀人蜂被网捕或 眼球草 捕获后会变为物品形态，其 新鲜度 会随时间降低，可以喂食任何 常规食物 以恢复其新鲜度；还会失去与其生物巢穴的联系，变为无家可归的蜜蜂。",
    ["kitcoon_nametag"] = "（Kit Collar） 是 饥荒：联机版 中的一种 可制作 物品。 小浣猫项圈用于为 小浣猫 取名字。鼠标点起小浣猫项圈再左键点击一只小浣猫会使小浣猫停下移动并弹出一个命名框，玩家可以手动键入小浣猫的名字或点击 随机 选取一个，然后再点击 命名 即可给小浣猫命名，随后小浣猫项圈会消失。如果命名过程中点击 取消，则小浣猫项圈会返回到角色的 物品栏。",
    ["kitcoondecor1"] = "是 饥荒：联机版 中的一类实体，包括 发条鼠玩具、 火鸡不倒翁 和 逗猫小鱼。 浣猫之年玩具属于猫玩具， 小浣猫 和 浣猫 会被浣猫之年玩具吸引并与其互动。 玩家也能与火鸡不倒翁和逗猫小鱼互动。",
    ["kitcoondecor1_kit"] = "是 饥荒：联机版 中的一类实体，包括 发条鼠玩具、 火鸡不倒翁 和 逗猫小鱼。 浣猫之年玩具属于猫玩具， 小浣猫 和 浣猫 会被浣猫之年玩具吸引并与其互动。 玩家也能与火鸡不倒翁和逗猫小鱼互动。",
    ["kitcoondecor2"] = "是 饥荒：联机版 中的一类实体，包括 发条鼠玩具、 火鸡不倒翁 和 逗猫小鱼。 浣猫之年玩具属于猫玩具， 小浣猫 和 浣猫 会被浣猫之年玩具吸引并与其互动。 玩家也能与火鸡不倒翁和逗猫小鱼互动。",
    ["kitcoondecor2_kit"] = "是 饥荒：联机版 中的一类实体，包括 发条鼠玩具、 火鸡不倒翁 和 逗猫小鱼。 浣猫之年玩具属于猫玩具， 小浣猫 和 浣猫 会被浣猫之年玩具吸引并与其互动。 玩家也能与火鸡不倒翁和逗猫小鱼互动。",
    ["kitcoonden"] = "（Kitcoon Nursery） 是 饥荒：联机版 中的一种建筑，在已供奉的 浣猫神龛 附近可以花费 1 个 幸运金块 制作小浣猫托儿所套装，然后将该套装布置到地面上以建造小浣猫托儿所。 跟随玩家的 小浣猫 在小浣猫托儿所附近时，玩家可以右键单击小浣猫来将其托管到托儿所。左键抚摸小浣猫即可让其再次跟随。",
    ["kitcoonden_kit"] = "（Kitcoon Nursery） 是 饥荒：联机版 中的一种建筑，在已供奉的 浣猫神龛 附近可以花费 1 个 幸运金块 制作小浣猫托儿所套装，然后将该套装布置到地面上以建造小浣猫托儿所。 跟随玩家的 小浣猫 在小浣猫托儿所附近时，玩家可以右键单击小浣猫来将其托管到托儿所。左键抚摸小浣猫即可让其再次跟随。",
    ["klaussackkey"] = "（Stag Antler） 是 饥荒：联机版 中的一种物品，由 克劳斯 二阶段死亡时掉落。 麋鹿茸可以打开 赃物袋，使用后消失。",
    ["koalefig_trunk"] = "（Fig-Stuffed Trunk） 是 饥荒：联机版 的一种 物品。 无花果酿象鼻只能由 烹饪 产生。烹饪配方为：至少有 1 个 无花果 / 熟无花果，至少有 1 个 象鼻 / 冬象鼻 / 象鼻排。优先级为 40，需要花费 40 秒。",
    ["krampus_sack"] = "（Krampus Sack） 是 饥荒：联机版 中的一种 物品。 坎普斯背包提供 14 个 物品栏，装备时，坎普斯背包的物品栏会显示在屏幕右侧，成为玩家物品栏的一部分，帮助玩家携带和管理更多的物品。 坎普斯背包只能被放入 装备栏，无法放入其他任何物品栏，意味着玩家一次只能携带一个装备的坎普斯背包，并且无法将它们放在 容器 里储存。",
    ["lantern"] = "（Lantern） 是 饥荒：联机版 中的一种 可制作 物品。 提灯可以装备在手部或放在地上，提供大范围的光照。可以用 荧光燃料 为其添加燃料。和 火坑 一样，随着燃料耗尽它的光照范围会逐渐缩小。 放在地上的提灯可以关闭，不再发光以节约燃料。",
    ["latkes"] = "（Winter's Feast Dishes） 是 饥荒：联机版 中的一类 可制作 物品，需要通过在 砖砌烤炉 旁制作来获得。 冬季盛宴菜肴可被放置在 冬季盛宴餐桌 上享用，以获得“冬季欢愉”增益，详见 冬季盛宴餐桌。 原文单词中“merry”通常用来指代圣诞期间的“快乐”，“berry sauce”则是果酱，莓果酱的意思；",
    ["lavae_cocoon"] = "（Chilled Lavae） 是 饥荒：联机版 中的一种 物品，由 超级可爱岩浆虫 被 冰冻 后掉落。 冷冻虫卵会被 鼹鼠 收集。",
    ["lavae_egg"] = "（Lavae Egg） 是 饥荒：联机版 中的一种 物品，由 龙蝇 死亡时掉落（33%概率），也有概率从 赃物袋 中开出。 与 高脚鸟蛋 类似，把岩浆虫卵放在任意 热源 附近 10 秒将使其开始孵化。 岩浆虫卵需要孵化 2 天，只有放在地上时才会进行孵化计时。孵化期间的岩浆虫卵必须时刻处于热源旁，否则它就会感到不适并停止孵化计时；",
    ["lavae_egg_cracked"] = "（Lavae Egg） 是 饥荒：联机版 中的一种 物品，由 龙蝇 死亡时掉落（33%概率），也有概率从 赃物袋 中开出。 与 高脚鸟蛋 类似，把岩浆虫卵放在任意 热源 附近 10 秒将使其开始孵化。 岩浆虫卵需要孵化 2 天，只有放在地上时才会进行孵化计时。孵化期间的岩浆虫卵必须时刻处于热源旁，否则它就会感到不适并停止孵化计时；",
    ["lavae_tooth"] = "（Lavae Tooth） 是 饥荒：联机版 中的一种 物品，由 岩浆虫卵 孵化时掉落。 超级可爱岩浆虫 会跟随岩浆虫尖牙，类似于 切斯特 跟随 眼骨 一样。 当所属的 超级可爱岩浆虫 死亡时，岩浆虫尖牙就会变为 灰烬。",
    ["lawn"] = "（Lawn Turf） 是 饥荒 中的一种 可制作 地皮，可使用 干草叉 挖 草坪地块 获取。 可以铺设于 空白地块，将其变为草坪地块。 草坪地块 是 饥荒 中的一种 地块，自然分布于 城镇布景。",
    ["leafloaf"] = "（Leafy Meatloaf） 是 饥荒：联机版 中的一种 物品。 叶肉糕只能由 烹饪 产生，烹饪配方为：至少有 2 个 叶肉 / 熟叶肉，优先级为 25，需要花费 40 秒。",
    ["leafymeatburger"] = "（Veggie Burger） 是 饥荒：联机版 中的一种 物品。 素食堡只能由 烹饪 产生。烹饪配方为：至少有 1 个 叶肉 / 熟叶肉，至少有 1 个 洋葱 / 烤洋葱， 蔬菜度 大于等于 2，优先级为 26，需要花费 40 秒。",
    ["leafymeatsouffle"] = "（Jelly Salad） 是 饥荒：联机版 中的一种 物品。 果冻沙拉只能由 烹饪 产生。烹饪配方为：至少 2 个 叶肉 / 熟叶肉， 甜味剂度 大于等于 2。优先级为 50，需要花费 40 秒。",
    ["leif_idol"] = "（Treeguard Idol） 是 饥荒：联机版 中的 可制作 物品。 树精守卫雕像 燃烧 成灰烬或作为 燃料 使用时会使周围 10 距离单位 1 距离单位等于 1/4 地块 边长，即一般情况下放置墙壁的最小间隔，也是建筑对齐网格的默认间隔。 内的 2×堆叠数量 棵未枯萎的 常青树、 粗壮常青树 或中等形态的 桦栗树 直接转变为 树精守卫 或 毒桦栗树。",
    ["lifeinjector"] = "（Booster Shot） 是 饥荒：联机版 中的一种 可制作 物品。 玩家可以使用它来恢复 告密的心、 绚丽之门、 溺水、 阴郁皮弗娄牛铃 等造成的 生命值上限惩罚，每个可以消除 25% 的生命值上限惩罚，相当于复活一次的损耗。",
    ["lifeplant"] = "（Magic Water） 是 饥荒 中的一种 物品。 魔力泉水可以种植于地面成为 魔力花。 同世界中魔力泉水和魔力花的存在会阻止 不老泉 产生新的魔力泉水。",
    ["lightbulb"] = "（Light Bulb） 是 饥荒：联机版 中的一种 物品。 荧光果放在地上时会发光，发光范围半径为 2.5 距离单位 1 距离单位等于 1/4 地块 边长，即一般情况下放置墙壁的最小间隔，也是建筑对齐网格的默认间隔。。",
    ["lightcrab"] = "（Crustashine） 是 饥荒：联机版 中的一种 生物。由 非自然传送门 生成。 与 兔子 类似，当玩家靠近时会快速跑开，可以用 陷阱 来抓住发光蟹。在玩家的物品栏中，发光蟹可以喂任何 常规食物 来恢复新鲜度。 发光蟹会靠近并进食附近 6 距离单位 1 距离单位等于 1/4 地块 边长，即一般情况下放置墙壁的最小间隔，也是建筑对齐网格的默认间隔。",
    ["lighter"] = "（Willow's Lighter） 是 饥荒：联机版 中的一种 可制作 物品。 薇洛 出生时自带 1 个薇洛的打火机。 薇洛的打火机（以下简称为 打火机）装备时会像 火炬 一样发光；在 雨 中，打火机耐久的损耗速度会随当前的降水速率而增加，最多变为原来的 150%；装备上打火机后对 可燃物 右键，便能点燃使其燃烧。",
    ["lightflier"] = "（Bulbous Lightbug） 是 饥荒：联机版 中的一种 可制作 生物，除制作外还可通过以下方式生成/获取： 球状光虫可以用 捕虫网 捕获。它会在 2 天内饿死，可以用 素食食物 喂食。 击杀球状光虫会为玩家增加 2 点 淘气值。",
    ["lightninggoathorn"] = "（Volt Goat Horn） 是 饥荒：联机版 中的一种 物品。 伏特羊角可作为食材放入锅中 烹饪，提供 1 不可食用度。",
    ["limestone"] = "（Limestone） 是 饥荒 中的一种 可制作 物品。",
    ["limpets"] = "（Limpets） 是 饥荒 中的一种 物品，由采摘 帽贝岩 或 残骸 获得，还有可能由 老虎机 生成 在 火源 上 烹饪 帽贝，就会变成 熟帽贝（Cooked Limpets）。 帽贝和熟帽贝可作为食材放入锅中 烹饪，提供 0.5 鱼度。",
    ["limpets_cooked"] = "（Limpets） 是 饥荒 中的一种 物品，由采摘 帽贝岩 或 残骸 获得，还有可能由 老虎机 生成 在 火源 上 烹饪 帽贝，就会变成 熟帽贝（Cooked Limpets）。 帽贝和熟帽贝可作为食材放入锅中 烹饪，提供 0.5 鱼度。",
    ["living_artifact"] = "（Living Artifact） 是 饥荒 中的一种 可制作 物品。其制作配方只能由 蓝图 解锁， 远古兵器 死亡时会掉落一个活性机甲的蓝图。 使用后会将其消耗，播放一段变身动画，同时会掉落 物品栏 中的全部物品。 类似于 海狸人，物品栏、制作栏、地图、生命饥饿理智潮湿值等GUI会从玩家屏幕上移除，仅剩下 昼夜 和变身的剩余时间显示。",
    ["livinglog"] = "（Living Log） 是 饥荒：联机版 中的一种 可制作 物品。",
    ["livingtree_root"] = "是 饥荒：联机版 中的一类 可制作 物品，只能在 疯狂科学家实验室 附近制作。 恐惧实验（Phobic Experiment），有 67% 概率产出 减轻恐惧的药液（Brew of Phobic Abatement），33% 概率产出 终止恐惧的药液（Brew of Phobic Abrogation）。",
    ["lobsterbisque"] = "（Lobster Bisque） 是 饥荒：联机版 中的一种 物品。 龙虾汤只能由 烹饪 产生。烹饪配方为：至少 1 个 龙虾， 冰度 大于 0。优先级为 30，需要花费 10 秒。",
    ["lobsterdinner"] = "（Lobster Dinner） 是 饥荒：联机版 中的一种 物品。 龙虾正餐是 麦斯威尔 的 最喜欢的食物。 龙虾正餐只能由 烹饪 产生。烹饪配方为：至少 1 只 龙虾，至少 1 块 黄油， 肉度 大于等于 1， 鱼度 大于等于 1，不能有 冰度。优先级为 25，需要花费 20 秒来烹饪。",
    ["log"] = "（Log） 是 饥荒：联机版 中的一种 可制作 物品。 砍倒树后留下的树桩用 铲子 挖掘可以得到 1 个木头。 码头 破裂掉落 1-2 个木头（平均 1.6 个）。",
    ["lotus_flower"] = "（Lotus Flower） 是 饥荒 中的一种 物品。由采集 睡莲 获得。 在火源上 烹饪 睡莲花，就会变成 熟莲藕（Cooked Lotus Root） 睡莲花可以被给予 收藏家，以换取 3 枚 呼噜币。",
    ["lotus_flower_cooked"] = "（Lotus Flower） 是 饥荒 中的一种 物品。由采集 睡莲 获得。 在火源上 烹饪 睡莲花，就会变成 熟莲藕（Cooked Lotus Root） 睡莲花可以被给予 收藏家，以换取 3 枚 呼噜币。",
    ["lucky_goldnugget"] = "（Lucky Gold Nugget） 是 饥荒：联机版 中的一种 物品，用于在各种 春节活动 中在激活后的神龛处换取物品。",
    ["lucy"] = "（Lucy the Axe） 是 饥荒：联机版 中的一种 物品。 伍迪 出生时自带 1 个露西斧。 当伍迪未携带露西斧时，使用 斧头 / 黄金斧头 / 月光玻璃斧 进行砍伐会将其转化为露西斧，同时原有的露西斧会转变为普通斧头（详见 #转化）。 露西斧被非 伍迪 玩家或 物品栏 中已经具有露西斧的伍迪捡起时，会立即从物品栏中掉出。",
    ["lunar_forge"] = "（Brightsmithy） 是 饥荒：联机版 中的一种 建筑。 辉煌铁匠铺是一个 制作站，靠近时可以制作辉煌铁匠铺分类中的物品： 使用 锤子 等摧毁或 拆解魔杖 解构辉煌铁匠铺将掉落它的制作材料，而不是掉落辉煌铁匠铺套装。",
    ["lunar_forge_kit"] = "（Brightsmithy） 是 饥荒：联机版 中的一种 建筑。 辉煌铁匠铺是一个 制作站，靠近时可以制作辉煌铁匠铺分类中的物品： 使用 锤子 等摧毁或 拆解魔杖 解构辉煌铁匠铺将掉落它的制作材料，而不是掉落辉煌铁匠铺套装。",
    ["lunar_seed"] = "（Celestial Jewel） 是 饥荒：联机版 中的一种 物品。 天体珠宝可以放入 启迪之冠 中，根据放入的数量改变其效果。 放置第 1 ~ 3 个 天体珠宝，每个将小虚影的攻击中一定比例的物理伤害转为等额的位面伤害；放置第 4 ~ 5 个珠宝，每个为小虚影的攻击增加 4.25 点物理伤害（所增加的伤害同样应用前者的转化）。",
    ["lunarplant_husk"] = "（Brightshade Husk） 是 饥荒：联机版 中一种 物品，击杀 致命亮茄 掉落。可用于制作多种装备。",
    ["lunarplant_kit"] = "亮茄修补套件（Brightshade Repair Kit） 是 饥荒：联机版 中的一种 可制作 物品。 亮茄修补套件可以为 亮茄头盔、 亮茄盔甲、 荆棘茄甲、 亮茄剑、 亮茄魔杖、 亮茄粉碎者 和 亮茄锄铲 修复 100% 的耐久。左键拿起亮茄修补套件，光标移动到需要修复的装备上，再点击右键即可修复。使用后消失。",
    ["lunarplanthat"] = "（Brightshade Helm） 是 饥荒：联机版 中的一种 可制作 物品。 亮茄头盔耐久耗尽后不会消失但无法装备，可以使用 亮茄修补套件 进行维修。 亮茄头盔在装备时提供以下特殊效果：",
    ["lureplantbulb"] = "（Fleshy Bulb） 是 饥荒：联机版 中的一种 可制作 物品。 食人花种子在 食人花 死亡后掉落 1 个。 食人花种子可以种植成食人花。",
    ["lutefisk"] = "（Winter's Feast Dishes） 是 饥荒：联机版 中的一类 可制作 物品，需要通过在 砖砌烤炉 旁制作来获得。 冬季盛宴菜肴可被放置在 冬季盛宴餐桌 上享用，以获得“冬季欢愉”增益，详见 冬季盛宴餐桌。 原文单词中“merry”通常用来指代圣诞期间的“快乐”，“berry sauce”则是果酱，莓果酱的意思；",
    ["machete"] = "（Machete） 和 黄金砍刀（Machete） 是 饥荒 中的一种 可制作 物品。砍刀自然生成于 坠毁的热气球布景、 草状装置布景。 砍刀可用于劈砍 竹林、 藤蔓 等 可劈砍 的物体。 黄金砍刀的用途与砍刀相同，但是耐久是砍刀的 4 倍。",
    ["magic_seal"] = "（Magic Seal） 是 饥荒 中的一种 物品，由 海豹 死亡或在消失时掉落。",
    ["magmafield"] = "（MAGMAFIELD Turf） 是 饥荒 中的一种 地皮。可以通过挖 岩浆地块 获得。 可以铺设于 空白地块，将其变为岩浆地块。",
    ["magnifying_glass"] = "（Magnifying Glass） 是 饥荒 中的一种 可制作 物品。 装备放大镜可以使对玩家有敌意的 蚁人 恐慌。 放大镜可以放入 炼钢炉 中冶炼为 合金。",
    ["malbatross_beak"] = "（Malbatross Bill） 是 饥荒：联机版 中的一种 物品，由 邪天翁 死亡后掉落，打开 赃物袋 有可能掉落存有邪天翁喙的包裹。 邪天翁喙作为船桨可以划 1500 次，向船施加的推力是普通桨的 2.66 倍。如果划得过快，邪天翁喙将会使玩家增加 9 点 并失去 6 点耐久度。邪天翁喙作为武器时每次攻击消耗 6 耐久。",
    ["malbatross_feather"] = "（Malbatross Feather） 是 饥荒：联机版 中的 物品，由 邪天翁 每次受伤掉落 0 - 4 根；邪天翁死亡后掉落 3 - 5 根，如果先前战斗中掉落的羽毛不足 24 根，则死亡掉落的羽毛数量会提升到补足到 24 根羽毛；用 锤子 摧毁 沉底宝箱 有 30% 概率获得 4- 10 根。可以作为合成材料使用，能制作 羽毛帆布 和 邪天翁羽浮漂。",
    ["malbatross_feathered_weave"] = "（Feathery Canvas） 是 饥荒：联机版 中的一种 可制作 物品。 羽毛帆布是制作 飞翼风帆套装 的材料之一。",
    ["mandrake"] = "（Mandrake） 是 饥荒：联机版 中的一种 生物。植物形态的曼德拉草自然生成于 曼德拉草森林群系。 曼德拉草十分稀有，每个 世界 平均只会生成 2 ~ 4 只曼德拉草。 若在白天被采摘曼德拉草会立即死亡变成物品形式的曼德拉草。",
    ["mandrake_active"] = "（Mandrake） 是 饥荒：联机版 中的一种 生物。植物形态的曼德拉草自然生成于 曼德拉草森林群系。 曼德拉草十分稀有，每个 世界 平均只会生成 2 ~ 4 只曼德拉草。 若在白天被采摘曼德拉草会立即死亡变成物品形式的曼德拉草。",
    ["mandrake_planted"] = "（Mandrake） 是 饥荒：联机版 中的一种 生物。植物形态的曼德拉草自然生成于 曼德拉草森林群系。 曼德拉草十分稀有，每个 世界 平均只会生成 2 ~ 4 只曼德拉草。 若在白天被采摘曼德拉草会立即死亡变成物品形式的曼德拉草。",
    ["mandrakesoup"] = "（Mandrake Soup） 是 饥荒：联机版 中的一种 物品。 曼德拉草汤只能由 烹饪 产生。烹饪配方为：至少有 1 个 曼德拉草。优先级为 10，需要花费 60 秒。",
    ["manrabbit_tail"] = "（Bunny Puff） 是 饥荒：联机版 中的一种 物品。 兔绒可以与 猪王 兑换 2 个 金块。 因为兔绒是 可怕食物， 猪人、 猎犬 和 蜘蛛 会吃掉地上的兔绒，也可以通过给猪人兔绒来雇佣猪人。",
    ["mapscroll"] = "（Map Scroll） 是 饥荒：联机版 中的可制造 物品。 角色在检查地图卷轴会说出这张卷轴是哪个玩家在哪一天画的。卷轴在创建时会记录制图的玩家当前地图的探索状态。被其他玩家学习后，学习地图卷轴的玩家地图中会添加卷轴的记录。因此，玩家可以组织分散式进行地图探索，通过这种方式更快地获得完整的地图记录。",
    ["mapscroll_tricker"] = "（Map Scroll） 是 饥荒：联机版 中的可制造 物品。 角色在检查地图卷轴会说出这张卷轴是哪个玩家在哪一天画的。卷轴在创建时会记录制图的玩家当前地图的探索状态。被其他玩家学习后，学习地图卷轴的玩家地图中会添加卷轴的记录。因此，玩家可以组织分散式进行地图探索，通过这种方式更快地获得完整的地图记录。",
    ["marble"] = "（Marble） 是 饥荒：联机版 中的一种 可制作 物品。 大理石可以摆在 陶轮 上来雕刻白色的 雕塑。",
    ["marblebean"] = "（Marble Bean） 是 饥荒：联机版 中的一种 可制作 物品。 大理石豌豆可以 种植 无法种植于 贫瘠地块、 水面地块。 于地面，成为 大理石芽。",
    ["marsh"] = "（Marsh Turf） 是 饥荒：联机版 中一种 可制作 地皮，可通过挖掘 沼泽地块 来获取。 大触手 死亡后有 25% 概率掉落 1 个。 可以放置在 泥土地块 上，使其变为沼泽地块。 沼泽地块 是 饥荒：联机版 中的一种 地块。",
    ["marsh_bush"] = "（Spiky Bush） 是 饥荒：联机版 中的一种 植物，主要生成于 恶地群系 和 大沼泽群系。 采摘尖刺灌木会获得 1 个 树枝，并对采摘者造成 3 点 物理伤害。穿戴 荆棘外壳 或 荆棘茄甲 可以完全免除伤害。 尖刺灌木采集后需要 4 天重新生长。若采摘时处于 春季，则再次生长所需的时间缩短为原来的 3/4。",
    ["mashedpotatoes"] = "（Creamy Potato Purée） 是 饥荒：联机版 中的一种 物品。 奶油土豆泥只能由 烹饪 产生。烹饪配方为：至少 2 个 土豆 / 烤土豆，至少 1 个 大蒜 / 烤大蒜，没有 肉度 和 不可食用度。优先级为 20，需要花费 20 秒。",
    ["mask_ancient_architecthat"] = "（Ancient Mask） 是 饥荒：联机版 中的一系列 物品，分别有鞘翅、远见者和工匠面具。 远古圣殿 的遗骸房间中会生成三种远古面具各一个，旁边伴有对应的 远古遗骸。 装备远古面具后玩家可以阅读 远古月符石、 圣殿月符石、 远古方尖碑 和 梦魇城墙，角色会说出上面记录的文字，从而让玩家了解 背景故事。",
