    ["teleportato_sw_ring"] = "装置（Thing） 或者玩家通常称呼的 传送装置（Teleportato） 是 饥荒 中的一系列实体。 生存模式世界 中会固定生成五件装置，分别位于各自的 布景 中，包括四件 物品 装置和一个装置底座；关于这些布景的信息，见 传送装置布景。",
    ["telescope"] = "（Spyglass） 是 饥荒 中的一种 可制作 物品。自然生成于某些 遗物布景。 伍德莱格 出生时自带 1 个望远镜。 装备望远镜后，可以向某一方向眺望，揭晓该方向前方约弧度 15 度、半径 200 距离单位 1 距离单位等于 1/4 地块 边长，即一般情况下放置墙壁的最小间隔，也是建筑对齐网格的默认间隔。 扇形范围内的 地图。",
    ["telestaff"] = "（Telelocator Staff） 是 饥荒：联机版 中的一种 可制作 物品。 传送魔杖是一件手部装备，使用距离 20 距离单位 1 距离单位等于 1/4 地块 边长，即一般情况下放置墙壁的最小间隔，也是建筑对齐网格的默认间隔。，可以对任何可移动的实体使用，如玩家角色和大部分的 生物。 在 森林世界 使用时，每次使用消耗玩家 50，将目标传送到其他位置；",
    ["temp_beta_msg"] = "（Beta Report） 是 饥荒：联机版 中的一种 物品。 在测试版中，游戏开发者有时会以测试版报告的形式给予更多有关后续更新的规划信息。 这些内容往往预示着现有游戏内容已经较为完整，但是后续的更新内容还有待添加。",
    ["tentaclespike"] = "（Tentacle Spike） 是 饥荒：联机版 中的一种 物品。",
    ["tentaclespots"] = "（Tentacle Spots） 是 饥荒：联机版 中的一种 物品。",
    ["terrarium"] = "（Terrarium） 是 饥荒：联机版 中的一种 物品，生成自 显眼箱子。 将盒中泰拉放到地上，可以触摸以启动它，此时盒中泰拉会发出音乐，盒子的外罩发出渐变循环的的红、绿、蓝光，向外散发绿色粒子效果，并进入轻微的漂浮状态。 启用后的盒中泰拉将会在 夜晚 到来时进入激活状态，发射一道光柱，照亮周围极大范围的区域。",
    ["thatchpack"] = "（Thatch Pack） 是 饥荒 中的一种 可制作 物品。 茅草袋提供 4 个 物品栏，装备时，茅草袋的物品栏会显示在屏幕右侧，成为玩家物品栏的一部分，帮助玩家携带和管理更多的物品。 茅草袋只能被放入 装备栏，无法放入其他任何物品栏，意味着玩家一次只能携带一个装备的茅草袋，并且无法将它们放在 容器 里储存。",
    ["thulecite"] = "（Thulecite） 是 饥荒：联机版 中的一种 可制作 物品。",
    ["thulecite_pieces"] = "（Thulecite Fragments） 是 饥荒：联机版 中的一种 物品。",
    ["thulecitebugnet"] = "（Thulecite Bug Net） 是 饥荒：联机版 中的一种 可制作 物品，其制作配方只能由学习以 琥珀美食 喂食 尘蛾 所获取的对应 稀有蓝图 来解锁。 铥矿捕虫网具有 捕虫网 10 倍的耐久，可以用来捕捉 萤火虫、 蜜蜂 等一类 可网捕 的实体，将它们收入到玩家的 物品栏 中。",
    ["thunderhat"] = "（Thunderhat） 是 饥荒 中的一种 可制作 物品。 装备雷帽时，装备者会像 避雷针 一样，吸引并吸收附近 40 距离单位 1 距离单位等于 1/4 地块 边长，即一般情况下放置墙壁的最小间隔，也是建筑对齐网格的默认间隔。 内的 闪电，使其不会引燃附近的 可燃物。 雷帽可以用 针线包 来修复耐久。",
    ["thurible"] = "（Shadow Thurible） 是 饥荒：联机版 中的一种 物品。 暗影香炉被装备或在地上时均会损失耐久，不像 提灯 一样可以关闭。耐久为 0 不消失。暗影香炉是 噩梦燃料消耗者。 耐久不为 0 的暗影香炉具有以下效果：",
    ["tidalmarsh"] = "（Tidal Marsh Turf） 是 饥荒 中的一种 地皮。可以通过挖 潮泽地块 获得。 可以铺设于 空白地块，将其变为潮泽地块。 潮泽地块 是 饥荒 中的一种 地块，自然分布于 潮汐沼泽区块、 TidalMermMarsh区块、 ToxicTidalMarsh区块。",
    ["tigereye"] = "（Eye of the Tiger Shark） 是 饥荒 中的一种 物品。",
    ["tiles"] = "（Ancient Tilework） 是 饥荒：联机版 中的一种 可制作 地皮，只能通过学习制作 废墟地皮蓝图 后得到的 稀有蓝图 解锁，可通过挖掘 远古瓷砖地块 来获取。 远古瓷砖的颜色会随着 梦魇循环 的周期性变化而变化。 可以放置在 泥土地块 上，使其变为远古瓷砖地块。",
    ["tiles_glow"] = "（Imitation Ancient Tilework） 是 饥荒：联机版 中的一种 可制作 地皮，只能通过学习制作 仿废墟地皮蓝图 后得到的 稀有蓝图 解锁，可通过挖掘 仿远古瓷砖地块 来获取。 可以放置在 泥土地块 上，使其变为仿远古瓷砖地块。 远古瓷砖地块 和 仿远古瓷砖地块 是 饥荒：联机版 中的一种 地块，自然分布于 遗迹。",
    ["tillweed"] = "（Weeds） 是 饥荒：联机版 中的一类作物。它们会干涉普通 农作物 的生长，给予 杂物压力，但它们本身的产物也会带来一定的好处。 饥荒：联机版 中共有四种杂草，分别是 必忘我（Forget-Me-Lots）、 犁地草（Tillweed）、 火荨麻（Fire Nettles）、 刺针旋花（Spiny Bindweed）。",
    ["tillweed_dried"] = "（Weeds） 是 饥荒：联机版 中的一类作物。它们会干涉普通 农作物 的生长，给予 杂物压力，但它们本身的产物也会带来一定的好处。 饥荒：联机版 中共有四种杂草，分别是 必忘我（Forget-Me-Lots）、 犁地草（Tillweed）、 火荨麻（Fire Nettles）、 刺针旋花（Spiny Bindweed）。",
    ["tillweedsalve"] = "（Tillweed Salve） 是 饥荒：联机版 中的一种 可制作 物品。 这是一种 医疗用品，可以用在角色或其他 生物 身上，回复 8。",
    ["tomato"] = "（Toma Root） 是 饥荒：联机版 中的一种 物品。可以通过采集 番茄植株 或摧毁 巨型番茄 获得。 番茄可以被给予 鸟笼 中的鸟，以换取 1 个 番茄种子。 在 火源 上 烹饪 番茄，就会变成 烤番茄（Roasted Toma Root）。",
    ["tomato_cooked"] = "（Toma Root） 是 饥荒：联机版 中的一种 物品。可以通过采集 番茄植株 或摧毁 巨型番茄 获得。 番茄可以被给予 鸟笼 中的鸟，以换取 1 个 番茄种子。 在 火源 上 烹饪 番茄，就会变成 烤番茄（Roasted Toma Root）。",
    ["tomato_oversized"] = "（Giant Vegetables） 是 饥荒：联机版 中的一类 物品，由收获对应巨型 农作物 获得。 巨型蔬果的保质期是对应作物的 4 倍。 腐烂 后变为对应的 巨型腐烂蔬果。 可以用 蜂蜡 为巨型蔬果打蜡，打蜡后变为对应的 打过蜡的巨型蔬果，不再腐烂。",
    ["tomato_oversized_rotten"] = "（Giant Vegetables） 是 饥荒：联机版 中的一类 物品，由收获对应巨型 农作物 获得。 巨型蔬果的保质期是对应作物的 4 倍。 腐烂 后变为对应的 巨型腐烂蔬果。 可以用 蜂蜡 为巨型蔬果打蜡，打蜡后变为对应的 打过蜡的巨型蔬果，不再腐烂。",
    ["tomato_oversized_waxed"] = "（Giant Vegetables） 是 饥荒：联机版 中的一类 物品，由收获对应巨型 农作物 获得。 巨型蔬果的保质期是对应作物的 4 倍。 腐烂 后变为对应的 巨型腐烂蔬果。 可以用 蜂蜡 为巨型蔬果打蜡，打蜡后变为对应的 打过蜡的巨型蔬果，不再腐烂。",
    ["tomato_seeds"] = "（Seeds） 是 饥荒：联机版 中的一种 物品。 种子可以栽种于 农田土壤，使其随机长出一种 农作物。种子的萌发时间是随机的，并且和作物是否应季有关。普通的种子在 秋季 和 春季 应季，在其发芽后根据长出的 农作物 或 杂草 决定。 种子长成的农作物种类的概率取决于季节，如果某些农作物在当前季节应季，则种子在该季节有更高概率长成这些农作物，其概率如下表。",
    ["tophat"] = "（Top Hat） 是 饥荒：联机版 中的一种 可制作 物品。 高礼帽的皮肤也可以应用于 灵子分解器 和 魔术师高礼帽。 织造-优雅 愚人帽 愚人系列 欢乐的小丑帽！",
    ["torch"] = "（Torch） 是 饥荒：联机版 中的一种 可制作 物品。 火炬装备时会发光；在 雨 中，火炬耐久的损耗速度会随当前的降水速率而增加，最多变为原来的 150%；装备上火炬后对 可燃物 右键，便能点燃使其燃烧。 使用火炬攻击有 50% 概率 受 幸运值 影响，点击 此处 展开详细计算方式与计算工具。 点燃攻击对象。",
    ["tourtiere"] = "（Winter's Feast Dishes） 是 饥荒：联机版 中的一类 可制作 物品，需要通过在 砖砌烤炉 旁制作来获得。 冬季盛宴菜肴可被放置在 冬季盛宴餐桌 上享用，以获得“冬季欢愉”增益，详见 冬季盛宴餐桌。 原文单词中“merry”通常用来指代圣诞期间的“快乐”，“berry sauce”则是果酱，莓果酱的意思；",
    ["townportaltalisman"] = "（Desert Stone） 是 饥荒：联机版 中的一种 物品，通过用 1 个 鸟蛋 或 玩具 喂食 蚁狮 换来 1 个；蚁狮死亡后掉落 6 ~ 8 个； 赃物袋 中开出的 捆绑物资 有概率含有沙之石。 沙之石可以制作 刮地皮头盔 和 懒人传送塔，也可以用于传送到懒人传送塔。",
    ["trailmix"] = "（Trail Mix） 是 饥荒：联机版 中的一种 物品。 什锦干果是 沃尔特 的 最喜欢的食物。 什锦干果只能由 烹饪 产生。烹饪配方为：至少 1 个 桦栗果 / 烤桦栗果，至少 1 个 浆果 / 烤浆果 / 多汁浆果 / 烤多汁浆果， 种子度 大于等于 1， 水果度 大于等于 1，不包含 肉度、 蔬菜度、 蛋度、 乳制品度。",
    ["transistor"] = "（Electrical Doodad） 是 饥荒：联机版 中的一种 可制作 物品。",
    ["trap"] = "（Trap） 是 饥荒：联机版 中的一种 可制作 物品。 陷阱可以放在地上来捕捉部分生物，一旦这些生物从陷阱附近通过，就会触发陷阱，把它罩在陷阱下，详细列表见 下文。 可以在陷阱中布置 诱饵物品 来吸引生物，布置的物品会在陷阱触发后被消耗。",
    ["trap_bramble"] = "（Bramble Trap） 是 饥荒：联机版 中的一种 可制作 物品。 荆棘陷阱需要右键安装在地上，当有 生物 是 怪物、 拟角色 或 动物；且不是 幽灵行者、 飞行单位、 鬼魂类、 玩家鬼魂；且不处于玩家进入游戏后 1.5 秒的保护时间内。",
    ["trap_fumarole"] = "（Coals） 是 饥荒：联机版 中的一种 可制作 物品。 煤炭需要右键安放置在地上，放置后的煤炭还可以被直接捡起来。类似于 墙，煤炭只能放置在指定的网格点位上，每个 地块 中有 2×2=4 个可供放置的此点位。",
    ["trap_starfish"] = "（Anenemy） 是 饥荒：联机版 中的一种实体。自然生成于 月岛碎片群系、 月岛海滩群系。 当有 生物 是 怪物、 拟角色 或 动物；且不是 幽灵行者、 飞行单位、 鬼魂类、 玩家鬼魂；且不处于玩家进入游戏后 1.5 秒的保护时间内。",
    ["trap_teeth"] = "（Tooth Trap） 是 饥荒：联机版 中的一种 可制作 物品。 犬牙陷阱需要右键安装在地上，当有 生物 是 怪物、 拟角色 或 动物；且不是 幽灵行者、 飞行单位、 鬼魂类、 玩家鬼魂；且不是玩家。 踩到它的时候，它便会被触发，对触发者造成伤害。 犬牙陷阱每次触发都会消耗耐久，并且需要玩家进行重置才能再次触发。",
    ["trawlnet"] = "（Trawl Net） 是 饥荒 中的一种 可制作 物品。 可以被装备到 船尾栏；装备后，玩家只需驾船驶过一些实体就能将其捕获为对应的 物品，或者每移动 100 距离单位 1 距离单位等于 1/4 地块 边长，即一般情况下放置墙壁的最小间隔，也是建筑对齐网格的默认间隔。 就会凭空捕获一个随机新物品。",
    ["trawlnetdropped"] = "（Trawl Net） 是 饥荒 中的一种 可制作 物品。 可以被装备到 船尾栏；装备后，玩家只需驾船驶过一些实体就能将其捕获为对应的 物品，或者每移动 100 距离单位 1 距离单位等于 1/4 地块 边长，即一般情况下放置墙壁的最小间隔，也是建筑对齐网格的默认间隔。 就会凭空捕获一个随机新物品。",
    ["tree_rock_seed"] = "（Boulderbough Seed） 是 饥荒：联机版 中的一种 物品。 巨石枝种子可以种植在地上得到 巨石枝。",
    ["treegrowthsolution"] = "（Tree Jam） 是 饥荒：联机版 中的一种 可制作 物品。 大副 死亡后会掉落它还没使用完的树果酱，挖掘 海盗藏匿处 也有概率获得树果酱。 对可施肥树木使用树果酱会使它们直接生长到下一个阶段。 树果酱是 肥料，能够提供 8 催长剂、32 堆肥 和 8 粪肥 的营养物质。",
    ["trident"] = "（Trident） 是 饥荒 中的一种 物品。 当玩家驾驶 船 使用三叉戟时，三叉戟的攻击将会造成 3 倍伤害，即 102 点伤害。",
    ["trim"] = "（Ancient Brickwork） 是 饥荒：联机版 中的一种 可制作 地皮，只能通过学习制作 废墟地皮蓝图 后得到的 稀有蓝图 解锁，可通过挖掘 远古砖雕地块 来获取。 远古砖雕的颜色会随着 梦魇循环 的周期性变化而变化。 可以放置在 泥土地块 上，使其变为远古砖雕地块。",
    ["trim_glow"] = "（Imitation Ancient Brickwork） 是 饥荒：联机版 中的一种 可制作 地皮，只能通过学习制作 废墟地皮蓝图 后得到的 稀有蓝图 解锁，可通过挖掘 仿远古砖雕地块 来获取。 可以放置在 泥土地块 上，使其变为仿远古砖雕地块。 仿远古砖雕地块 是 饥荒：联机版 中的一种 地块，自然分布于 遗迹。",
    ["trinket_1"] = "（Trinkets） 是 饥荒：联机版 中的一类 物品，其中代码为 trinket_1~31 的物品属于普通玩具，代码为 trinket_32~46 的物品属于 万圣节小玩具。 一些玩具有着其他的获取方式和功能，例如：棋子玩具可以在当前世界解锁后由采集 风滚草 获取； 硬化橡胶塞 和 弯曲的叉子 分别能作为 海钓竿 的 浮标 和 鱼饵；",
